    def test_valid_email_with_dots(self):
        """Test email with dots in local part."""
        result = parse_email("john.doe@sub.domain.co.uk")
        assert result == {'local': 'john.doe', 'domain': 'sub.domain.co.uk'}

    def test_valid_email_with_plus(self):
        """Test email with plus sign (common in Gmail)."""
        result = parse_email("user+tag@gmail.com")
        assert result == {'local': 'user+tag', 'domain': 'gmail.com'}

    def test_valid_email_with_hyphen(self):
        """Test email with hyphens."""
        result = parse_email("first-last@my-domain.com")
        assert result == {'local': 'first-last', 'domain': 'my-domain.com'}

    # ==================== EDGE CASES ====================

    def test_empty_string(self):
        """Test empty string input."""
        assert parse_email("") is None

    def test_none_input(self):
        """Test None input (should not raise exception)."""
        assert parse_email(None) is None

    def test_whitespace_only(self):
        """Test string with only whitespace."""
        assert parse_email("   ") is None
        assert parse_email("\t\n") is None

    def test_single_at_sign(self):
        """Test just '@' character."""
        assert parse_email("@") is None

    def test_local_part_only(self):
        """Test email with only local part (no domain)."""
        assert parse_email("username@") is None

    def test_domain_only(self):
        """Test email with only domain (no local part)."""
        assert parse_email("@example.com") is None

    def test_multiple_at_signs(self):
        """Test email with multiple @ signs."""
        assert parse_email("user@name@example.com") is None
