    def test_no_dot_in_domain(self):
        """Test domain without a dot (invalid per function logic)."""
        assert parse_email("user@example") is None
        assert parse_email("user@com") is None

    def test_dot_at_start_of_domain(self):
        """Test domain starting with dot."""
        assert parse_email("user@.example.com") is None

    def test_dot_at_end_of_domain(self):
        """Test domain ending with dot."""
        assert parse_email("user@example.com.") is None

    def test_very_long_email(self):
        """Test very long but valid email (within reasonable limits)."""
        local = "a" * 30
        domain = "b" * 20 + ".com"
        result = parse_email(f"{local}@{domain}")
        assert result == {'local': local, 'domain': domain}

    # ==================== ERROR CASES & TYPE HANDLING ====================

    def test_non_string_input_integer(self):
        """Test integer input."""
        assert parse_email(123) is None

    def test_non_string_input_list(self):
        """Test list input."""
        assert parse_email(["test@example.com"]) is None

