            result = parse_email(email)
            assert result == {'local': f"user{char}name", 'domain': 'example.com'}

    def test_unicode_in_local_part(self):
        """Test unicode characters in local part."""
        result = parse_email("héllo@world.com")
        assert result == {'local': 'héllo', 'domain': 'world.com'}

    def test_unicode_in_domain(self):
        """Test unicode characters in domain."""
        result = parse_email("user@exämple.com")
        assert result == {'local': 'user', 'domain': 'exämple.com'}
